import React, { useEffect, useState, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  User, Shield, Mail, Trash2, Save, 
  Loader2, Crown, Users, Key, ChevronDown, 
  Settings, Zap, CheckCircle2, Lock, X
} from 'lucide-react';

const Perfil = () => {
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [usuarioSelecionado, setUsuarioSelecionado] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  
  const [loading, setLoading] = useState(true);
  const [novoNome, setNovoNome] = useState('');
  const [novoEmail, setNovoEmail] = useState(''); // Estado para o e-mail
  const [novaSenha, setNovaSenha] = useState('');

  const fecharSelecao = useCallback(() => {
    setUsuarioSelecionado(null);
    setIsModalOpen(false);
    setNovaSenha('');
  }, []);

  useEffect(() => {
    const handleEsc = (event) => { if (event.keyCode === 27) fecharSelecao(); };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [fecharSelecao]);

  useEffect(() => { carregarDados(); }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: meuPerfil } = await supabase.from('profiles').select('*').eq('id', user.id).maybeSingle();

      if (meuPerfil) {
        setPerfilLogado(meuPerfil);
        const { data: lista } = await supabase.from('profiles').select('*').order('nome', { ascending: true });
        if (lista) setUsuarios(lista);
      }
    } catch (err) { 
        console.error("Erro ao carregar dados:", err);
    } finally { setLoading(false); }
  };

  const selecionarUsuario = (user) => {
    if (perfilLogado?.tipo_usuario !== 'proprietario' && user.id !== perfilLogado?.id) return;

    setUsuarioSelecionado(user);
    setNovoNome(user.nome || '');
    setNovoEmail(user.email || ''); // Inicializa o campo de e-mail
    
    if (perfilLogado?.tipo_usuario === 'proprietario' && user.id !== perfilLogado.id) {
      setIsModalOpen(true);
    }
  };

  const atualizarNome = async () => {
    const { error } = await supabase.from('profiles').update({ nome: novoNome }).eq('id', usuarioSelecionado.id);
    if (!error) {
      if (usuarioSelecionado.id === perfilLogado.id) setPerfilLogado({ ...perfilLogado, nome: novoNome });
      setUsuarios(usuarios.map(u => u.id === usuarioSelecionado.id ? { ...u, nome: novoNome } : u));
      alert("✨ Nome atualizado com sucesso!");
    }
  };

  // FUNÇÃO PARA ATUALIZAR E-MAIL (Auth + Profile)
  const atualizarEmail = async () => {
    if (!novoEmail.includes('@')) return alert("E-mail inválido");

    // 1. Atualiza no Auth do Supabase (Login)
    const { error: authError } = await supabase.auth.updateUser({ email: novoEmail });
    
    if (authError) {
      alert("Erro ao atualizar e-mail de login: " + authError.message);
      return;
    }

    // 2. Atualiza na nossa tabela de profiles
    const { error: profileError } = await supabase.from('profiles').update({ email: novoEmail }).eq('id', usuarioSelecionado.id);
    
    if (!profileError) {
      if (usuarioSelecionado.id === perfilLogado.id) setPerfilLogado({ ...perfilLogado, email: novoEmail });
      setUsuarios(usuarios.map(u => u.id === usuarioSelecionado.id ? { ...u, email: novoEmail } : u));
      alert("📧 E-mail atualizado! Verifique sua caixa de entrada para confirmar a mudança.");
    }
  };

  const atualizarSenha = async () => {
    if (novaSenha.length < 6) return alert("A senha deve ter no mínimo 6 caracteres.");
    
    const { error } = await supabase.auth.updateUser({ password: novaSenha });
    
    if (!error) {
      alert("🔒 Senha alterada com sucesso!");
      setNovaSenha('');
    } else {
      alert("Erro ao alterar senha: " + error.message);
    }
  };

  const mudarCargo = async (usuarioId, novoCargo) => {
    const { error } = await supabase.from('profiles').update({ tipo_usuario: novoCargo }).eq('id', usuarioId);
    if (!error) {
      setUsuarios(usuarios.map(u => u.id === usuarioId ? { ...u, tipo_usuario: novoCargo } : u));
      setUsuarioSelecionado(prev => ({ ...prev, tipo_usuario: novoCargo }));
    }
  };

  const excluirUsuario = async (id, nome) => {
    if (window.confirm(`Remover permanentemente ${nome}?`)) {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (!error) {
        setUsuarios(usuarios.filter(u => u.id !== id));
        fecharSelecao();
      }
    }
  };

  if (loading) return <div style={containerCenter}><Loader2 className="animate-spin" size={48} color="#6366f1" /></div>;

  return (
    <div style={pageWrapper}>
      <div style={contentContainer}>
        
        <header style={headerStyle}>
          <div style={iconBadge}><Settings size={28} color="#fff" /></div>
          <div>
            <h1 style={mainTitle}>Gestão de Conta</h1>
            <p style={subTitle}>Clique no seu nome para editar seu perfil</p>
          </div>
        </header>

        <section style={{ marginBottom: '40px' }}>
          <div style={adminHeader}>
            <Users size={24} color="#0f172a" />
            <h2 style={adminTitle}>Lista de Membros</h2>
            <span style={userCountBadge}>{usuarios.length} membros</span>
          </div>
          <div style={userTableWrapper}>
            {usuarios.map(u => {
              const ehMeusDados = u.id === perfilLogado?.id;
              const podeClicar = perfilLogado?.tipo_usuario === 'proprietario' || ehMeusDados;

              return (
                <div 
                  key={u.id} 
                  style={{
                    ...userRow, 
                    border: usuarioSelecionado?.id === u.id ? '2px solid #6366f1' : '1px solid #f1f5f9',
                    opacity: podeClicar ? 1 : 0.6,
                    cursor: podeClicar ? 'pointer' : 'not-allowed'
                  }} 
                  onClick={() => selecionarUsuario(u)}
                >
                  <div style={userAvatarContainer}>
                    {u.tipo_usuario === 'proprietario' ? <Crown size={16} color="#eab308" /> : u.nome?.charAt(0)}
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={userName}>{u.nome} {ehMeusDados && " (Você)"}</div>
                    <div style={userEmail}>{u.email}</div>
                  </div>
                  <div style={badgeStyle(u.tipo_usuario)}>{u.tipo_usuario}</div>
                </div>
              );
            })}
          </div>
        </section>

        {usuarioSelecionado && usuarioSelecionado.id === perfilLogado?.id && (
          <div style={gridContainer}>
            <div style={glassCard}>
              <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '20px'}}>
                <div style={cardHeader}><Zap size={18} color="#6366f1" /><h3 style={cardTitle}>Meus Dados</h3></div>
                <button onClick={fecharSelecao} style={closeBtn}><X size={20} /></button>
              </div>
              
              <div style={inputGroup}>
                <label style={premiumLabel}>Nome Completo</label>
                <div style={inputWrapper}>
                  <User size={18} style={inputIcon} />
                  <input value={novoNome} onChange={(e) => setNovoNome(e.target.value)} style={premiumInput} />
                  <button onClick={atualizarNome} style={saveActionBtn}><CheckCircle2 size={18} /></button>
                </div>
              </div>

              {/* CAMPO DE E-MAIL EDITÁVEL */}
              <div style={inputGroup}>
                <label style={premiumLabel}>E-mail de Login</label>
                <div style={inputWrapper}>
                  <Mail size={18} style={inputIcon} />
                  <input value={novoEmail} onChange={(e) => setNovoEmail(e.target.value)} style={premiumInput} />
                  <button onClick={atualizarEmail} style={saveActionBtn}><CheckCircle2 size={18} /></button>
                </div>
              </div>

              <div style={staticInfoGroup}>
                <div style={infoBox}><label style={premiumLabel}>Nível de Acesso</label><div style={{...badgeStyle(usuarioSelecionado.tipo_usuario), marginTop: '5px', display: 'inline-block'}}>{usuarioSelecionado.tipo_usuario}</div></div>
              </div>
            </div>

            <div style={glassCard}>
              <div style={cardHeader}><Lock size={18} color="#f43f5e" /><h3 style={cardTitle}>Segurança</h3></div>
              <div style={inputGroup}>
                <label style={premiumLabel}>Nova Senha</label>
                <div style={inputWrapper}>
                  <Key size={18} style={inputIcon} />
                  <input type="password" placeholder="Mínimo 6 caracteres" value={novaSenha} onChange={(e) => setNovaSenha(e.target.value)} style={premiumInput} />
                </div>
              </div>
              <button onClick={atualizarSenha} style={gradientBtn}>Atualizar Senha</button>
            </div>
          </div>
        )}

        {isModalOpen && usuarioSelecionado && (
          <div style={modalOverlay} onClick={(e) => e.target === e.currentTarget && fecharSelecao()}>
            <div style={modalContent}>
              <div style={modalHeader}>
                <h3 style={adminTitle}>Gerenciar Acesso</h3>
                <button onClick={fecharSelecao} style={closeBtn}><X size={24} /></button>
              </div>
              <div style={userRowSimple}>
                <div style={userAvatarContainer}>{usuarioSelecionado.nome?.charAt(0)}</div>
                <div>
                  <div style={userName}>{usuarioSelecionado.nome}</div>
                  <div style={userEmail}>{usuarioSelecionado.email}</div>
                </div>
              </div>
              <div style={{marginTop: '25px'}}>
                <label style={premiumLabel}>Tipo de Conta</label>
                <div style={selectContainer}>
                  <select 
                    value={usuarioSelecionado.tipo_usuario} 
                    onChange={(e) => mudarCargo(usuarioSelecionado.id, e.target.value)}
                    style={modalSelect}
                  >
                    <option value="comum">Usuário Comum</option>
                    <option value="proprietario">Proprietário / Admin</option>
                  </select>
                  <ChevronDown size={18} style={selectChevron} />
                </div>
              </div>
              <div style={{marginTop: '40px', display: 'flex', gap: '12px'}}>
                <button onClick={() => excluirUsuario(usuarioSelecionado.id, usuarioSelecionado.nome)} style={deleteFullBtn}>
                  <Trash2 size={18} /> Excluir
                </button>
                <button onClick={fecharSelecao} style={cancelBtn}>Finalizar</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

